async (params, browser) => {
  // Search SoundCloud
  await browser.open(`https://soundcloud.com/search/sounds?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('.searchList__item, [class*=\'soundList__item\'], .sound__content, li[class*=\'searchList\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract track results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('.searchList__item, [class*="soundList__item"], li[class*="searchList"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const titleEl = el.querySelector('.soundTitle__title span, a[class*="soundTitle"] span, [class*="sound-title"]'); const artistEl = el.querySelector('.soundTitle__username, a[class*="soundTitle__username"], [class*="artist"]'); const playsEl = el.querySelector('[class*="playbackCount"], [class*="plays"], [title*="plays"]'); const likesEl = el.querySelector('[class*="likeCount"], [class*="likes"], [title*="likes"]'); const durationEl = el.querySelector('[class*="duration"], .playbackTimeline__duration span'); const genreEl = el.querySelector('[class*="genre"], .soundTitle__tagContent'); const linkEl = el.querySelector('a[href*="/"][class*="soundTitle__title"], a.soundTitle__title'); const imgEl = el.querySelector('.image__full, img[src*="sndcdn"], .sc-artwork img'); const repostsEl = el.querySelector('[class*="repostCount"], [title*="reposts"]'); results.push({ title: titleEl ? titleEl.textContent.trim() : '', artist: artistEl ? artistEl.textContent.trim() : '', plays: playsEl ? playsEl.textContent.trim() : '', likes: likesEl ? likesEl.textContent.trim() : '', reposts: repostsEl ? repostsEl.textContent.trim() : '', duration: durationEl ? durationEl.textContent.trim() : '', genre: genreEl ? genreEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
